async (params, browser) => {
  // Search hotels on Expedia
  await browser.open(`https://www.expedia.com/Hotel-Search?destination=${params.destination}&startDate=${params.checkin}&endDate=${params.checkout}&adults=2`)

  // Wait for hotel results
  await browser.waitForSelector('[data-stid=\'lodging-card-responsive\'], [data-stid=\'property-listing\']', 20000)

  // Let results render
  await browser.wait(3000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract hotel results
  const hotel_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('[data-stid="lodging-card-responsive"], [data-stid="property-listing"]'); for (let i = 0; i < Math.min(items.length, 15); i++) { const el = items[i]; const nameEl = el.querySelector('h3, h2'); const ratingEl = el.querySelector('span.is-visually-hidden, [aria-label*="rating"]'); const priceEl = el.querySelector('[data-test-id="price-summary-message-line"] span, [data-stid="price-lockup"] span'); const imgEl = el.querySelector('img'); const linkEl = el.querySelector('a[data-stid="open-hotel-information"], a[href*="Hotel-Information"], a[href*=".h"]'); const neighborhoodEl = el.querySelector('[data-stid="content-hotel-neighborhood"], [class*="neighborhood"]'); const amenityEls = el.querySelectorAll('[data-stid="amenity-icon"] span, [aria-label*="amenity"]'); const amenities = []; amenityEls.forEach(function(a) { const t = a.textContent.trim(); if (t && t.length < 50) amenities.push(t); }); const reviewCountEl = el.querySelector('[data-stid="reviews"] span, [aria-label*="reviews"]'); const url = linkEl ? (linkEl.href.startsWith('http') ? linkEl.href : 'https://www.expedia.com' + linkEl.getAttribute('href')) : ''; results.push({ name: nameEl ? nameEl.textContent.trim() : '', guest_rating: ratingEl ? ratingEl.textContent.trim() : '', review_count: reviewCountEl ? reviewCountEl.textContent.trim() : '', price: priceEl ? priceEl.textContent.trim() : '', neighborhood: neighborhoodEl ? neighborhoodEl.textContent.trim() : '', amenities: amenities.slice(0, 5), image: imgEl ? imgEl.getAttribute('src') : '', url: url }); } return { destination: params.destination, checkin: params.checkin, checkout: params.checkout, result_count: results.length, results: results }`)

  return hotel_results
}
